// 蓝图
class Animal {
  constructor(name) { this.name = name; }
  speak() { return `${this.name}叫`; }
}

// 根据蓝图建实例
const dog = new Animal("旺财");
console.log(dog.speak());  // "旺财叫"

class Person {
  constructor(name, age) {       // 构造函数，new 时自动调用
    this.name = name;              // 实例属性
    this.age = age;
  }

  greet() {                        // 实例方法（挂在 prototype 上）
    return `你好，我是${this.name}`;
  }

  static create(name) {            // 静态方法（挂在类本身上）
    return new Person(name, 30);
  }
}

const p = new Person("小明", 25);
console.log(p.greet());           // "你好，我是小明"
console.log(Person.create("小红").greet()); // "你好，我是小红"

