function Animal(name) { this.name = name; }
Animal.prototype.speak = function() { return `${this.name}叫`; };

const cat = new Animal("咪咪");

// 原型链验证
console.log(cat.__proto__ === Animal.prototype);        // true
console.log(Animal.prototype.__proto__ === Object.prototype); // true
console.log(Object.prototype.__proto__);                // null（链的终点）

// 属性查找过程
console.log(cat.name);   // ① cat 自身 → 找到 "咪咪"
console.log(cat.speak);  // ① cat 自身 → 没有
                         // ② cat.__proto__ (Animal.prototype) → 找到 speak

class Animal {
  constructor(name, sound) {
    this.name = name;
    this.sound = sound;
  }
  speak() { return `${this.name}说：${this.sound}！`; }
}

class Dog extends Animal {
  constructor(name) {
    super(name, "汪汪");  // 必须先调 super()！
  }
  fetch(item) { return `${this.name}捡回了${item}`; }  // 新增方法
}

class Cat extends Animal {
  constructor(name) { super(name, "喵喵"); }
  speak() { return super.speak() + "～"; }  // 重写+扩展
}

console.log(new Dog("旺财").speak());   // "旺财说：汪汪！"
console.log(new Cat("咪咪").speak());   // "咪咪说：喵喵！～"

// 组合继承 = 原型链继承 + 构造函数继承
function Parent(name) { this.name = name; }
Parent.prototype.say = function() { return this.name; };

function Child(name, age) {
  Parent.call(this, name);  // 构造函数继承：继承属性
  this.age = age;
}
Child.prototype = Object.create(Parent.prototype); // 原型链继承：继承方法
Child.prototype.constructor = Child;  // 修复 constructor

const c = new Child("小明", 25);
console.log(c.say());  // "小明"

class Animal {
  constructor(name) { this.name = name; }
  speak() { return `${this.name}发出声音`; }
}
class Dog extends Animal {
  speak() { return `${this.name}汪汪`; }
  fetch() { return `${this.name}捡球`; }
}
class Cat extends Animal {
  speak() { return `${this.name}喵喵`; }
}

// 多态：同一接口，不同行为
const animals = [new Dog("旺财"), new Cat("咪咪")];
animals.forEach(a => console.log(a.speak()));
// "旺财汪汪"  "咪咪喵喵"

// instanceof 检查继承关系
const dog = new Dog("旺财");
console.log(dog instanceof Dog);    // true
console.log(dog instanceof Animal); // true
console.log(dog instanceof Object); // true

// ✅ class 定义
class Name {
  constructor() { /* 初始化 */ }
  method() { /* 实例方法 */ }
  static method() { /* 静态方法 */ }
  get prop() { /* getter */ }
  set prop(v) { /* setter */ }
}

// ✅ 继承
class Child extends Parent {
  constructor() { super(); /* 必须先 super */ }
  method() { super.method(); /* 调用父类 */ }
}

// ✅ 原型链检查
Object.getPrototypeOf(obj)  // 获取原型
obj instanceof ClassName     // 检查继承关系
